rollback.sql:
DELETE FROM permissions WHERE code IN
              ('DOCUMENT_CREATE','DOCUMENT_REVIEW','DOCUMENT_APPROVE','DOCUMENT_OBSOLETE',
               'CHANGE_CREATE','CHANGE_APPROVE','AUDIT_VIEW','USER_MANAGE');

changeSet.sql:
-- ADMIN: all permissions INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r CROSS JOIN permissions p WHERE r.name = 'ADMIN';
-- QA_MANAGER: review/approve documents + approve changes + view audit INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('DOCUMENT_REVIEW','DOCUMENT_APPROVE','CHANGE_APPROVE','AUDIT_VIEW') WHERE r.name = 'QA_MANAGER';
-- REVIEWER: review documents + view audit INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('DOCUMENT_REVIEW','AUDIT_VIEW') WHERE r.name = 'REVIEWER';
-- AUTHOR: create documents + create changes INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('DOCUMENT_CREATE','CHANGE_CREATE') WHERE r.name = 'AUTHOR'; -- OPERATOR: no permissions by default
